import streamlit as st

st.title("Calculadora IMC 🧮")
st.subheader("Meu primeiro programa Streamlit 🤘🏻")

altura = st.number_input("Digite a sua altura: ", min_value = 0.0)
peso = st.number_input("Digite o seu peso: ", min_value = 0.0)

if st.button("calcular"):
    imc = peso / altura ** 2
    st.success(f"Seu IMC é: {imc: .2f}")

    if imc <18.5:
        st.image("https://th.bing.com/th/id/OIP.EonBJkIeVaQqNokfwiABdgHaEK?w=301&h=180&c=7&r=0&o=5&pid=1.7" ,width=300)
        st.error("Abaixo do peso.")
    elif imc <24.9:
        st.image("https://th.bing.com/th?q=GIF+Comunica%c3%a7%c3%a3o+OK&w=120&h=120&c=1&rs=1&qlt=70&o=7&cb=1&pid=InlineBlock&rm=3&mkt=pt-BR&cc=BR&setlang=pt-br&adlt=moderate&t=1&mw=247" ,width=300)
        st.success("Peso normal.")
    elif imc <29.9:
        st.image("https://th.bing.com/th/id/OIP.Fk0pOw7z_QaGWNaNoJonTgHaE8?w=258&h=180&c=7&r=0&o=5&pid=1.7" ,width=300)
        st.error("Sobrepeso.")
    elif imc <34.9:
        st.image("data:image/jpeg;base64," ,width=300)
        st.error("Obesidade Grau I.")
    elif imc <39.9:
        st.image("data:image/jpeg;base64," ,width=300)
        st.error("Obesidade Grau II.")
    else:
        st.image("https://th.bing.com/th/id/OIP.4kqi5dUeBk2d4yvQIPFVEwHaE8?w=265&h=180&c=7&r=0&o=5&pid=1.7" ,width=300)
        st.error("Obesidade Grau III (mórbida).")